function standard_deviation = noise_checker(image)  %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  % 元画像とmedianフィルタを掛けた元画像の差の標準偏差を出力  %  %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  median_size = 0.05;  [h, w] = size(image);  % 画像サイズのmedian_sizeに近い奇数を生成  median_h = 2 * round((h*median_size - 1)/2) + 1;  median_w = 2 * round((w*median_size - 1)/2) + 1;  noise_diff = image - imsmooth(image, "Median", [median_h, median_w]);  standard_deviation = std(noise_diff(:));end